\section*{Explicação didática}

\textbf{Explicação curta:} O efeito Doppler faz com que, na aproximação da ambulância, a frequência das ondas refletidas aumente, tornando o som da sirene percebido pelo operador mais agudo; assim, \(f_r > f_0\).

\textbf{Passo a passo:}
\begin{enumerate}
  \item Reconheça que o som da sirene tem frequência \(f_0\).
  \item O radar emite ondas de rádio de frequência \(f_0\) que são refletidas pela ambulância.
  \item Devido ao movimento da ambulância na direção do radar, ocorre o efeito Doppler nas ondas refletidas.
  \item Na aproximação, a frequência das ondas refletidas medidas é maior que a original, ou seja, \(f_r > f_0\).
  \item Consequentemente, o operador percebe o som da sirene mais agudo.
\end{enumerate}

\textbf{Armadilhas comuns:}
\begin{itemize}
  \item Pensar que a frequência diminui na aproximação, tornando o som mais grave.
  \item Confundir as frequências do som da sirene e das ondas de rádio refletidas.
  \item Achar que a frequência medida pelo radar permanece igual à frequência emitida.
  \item Interpretar erroneamente que um som mais agudo corresponde a frequência menor.
\end{itemize}

\textbf{Dicas para o ensino:}
\begin{itemize}
  \item Explique com exemplos cotidianos, como sirenes de ambulância ou apitos de trem.
  \item Destaque a diferença entre as frequências do som e das ondas de rádio refletidas.
  \item Use representações visuais para ilustrar o movimento e o efeito Doppler.
  \item Reforce que sons mais agudos têm frequência maior.
  \item Proponha exercícios relacionando movimento, frequência e percepção sonora.
\end{itemize}

